112	static void *time_source_realtime_thread(void *ts)
113	{
114	  time_source_realtime_t *time_source = ts;
115	
116	  struct timespec now;
117	  if (clock_gettime(CLOCK_MONOTONIC, &now) == -1)
118	    AssertFatal(0, "clock_gettime failed\n");
119	
120	  /* go to next millisecond */
121	  now = next_ms(now);
122	
123	  while (!time_source->common.exit) {
124	    /* sleep */
125	    if (clock_nanosleep(CLOCK_MONOTONIC, TIMER_ABSTIME, &now, NULL) == -1) {
126	      /* accept interruption by signals and then simply restart the sleep */
127	      if (errno == EINTR)
128	        continue;
129	      AssertFatal(0, "clock_nanosleep failed\n");
130	    }
131	
132	    if (time_source->common.exit)
133	      break;
134	
135	    /* tick */
136	    lock(&time_source->common);
137	    void (*callback)(void *callback_data) = time_source->common.callback;
138	    void *callback_data = time_source->common.callback_data;
139	    unlock(&time_source->common);
140	    if (callback != NULL)
141	      callback(callback_data);
142	
143	    /* go to next millisecond */
144	    now = next_ms(now);
145	  }
146	
147	  return (void *)0;
148	}
